`timescale 1ns/1ps
`default_nettype none

module accumulator #(
    parameter integer ARRAY_SIZE = 8,
    parameter integer ACC_WIDTH = 32,
    parameter integer ACC_DEPTH_BITS = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic valid_in, 
    input  logic [ARRAY_SIZE*ACC_WIDTH-1:0] mxu_data_in,
    input  logic accumulate_en, 
    input  logic [ACC_DEPTH_BITS-1:0] write_row_addr,
    input  logic [ACC_DEPTH_BITS-1:0] drain_read_addr,
    output logic [ARRAY_SIZE*ACC_WIDTH-1:0] drain_data_out
);

    // -------------------------------------------------------------------------
    // Memory Definition
    // -------------------------------------------------------------------------
    localparam MEM_DEPTH = 1 << ACC_DEPTH_BITS;
    localparam TOTAL_WIDTH = ARRAY_SIZE * ACC_WIDTH;

    // Use reg to help simulator inference
    reg [TOTAL_WIDTH-1:0] mem [0:MEM_DEPTH-1];

    // Pipeline Registers
    logic [TOTAL_WIDTH-1:0]    p1_mxu_data;
    logic [ACC_DEPTH_BITS-1:0] p1_write_addr;
    logic                      p1_valid;
    logic                      p1_accumulate_en;

    // Explicit read register for Compute Port
    logic [TOTAL_WIDTH-1:0]    mem_rdata_compute; 

    // -------------------------------------------------------------------------
    // 1. Compute Port Read (Stage 0) - ISOLATED BLOCK
    // -------------------------------------------------------------------------
    // Isolating this read is critical for correct RAM inference in simulation.
    // This ensures the simulator treats the compute read as a distinct port.
    always_ff @(posedge clk) begin
        if (reset)
            mem_rdata_compute <= '0;
        else
            mem_rdata_compute <= mem[write_row_addr];
    end

    // -------------------------------------------------------------------------
    // 2. Compute Logic (Combinatorial)
    // -------------------------------------------------------------------------
    logic [TOTAL_WIDTH-1:0] write_data_comb;
    logic [ACC_WIDTH-1:0]   val_old [ARRAY_SIZE-1:0];
    logic [ACC_WIDTH-1:0]   val_new [ARRAY_SIZE-1:0];
    logic [ACC_WIDTH-1:0]   val_sum [ARRAY_SIZE-1:0];
    logic [ACC_WIDTH-1:0]   val_result [ARRAY_SIZE-1:0];

    integer i;
    always_comb begin
        write_data_comb = '0; 
        for (i = 0; i < ARRAY_SIZE; i = i + 1) begin
            // 1. Unpack using Indexed Part-Select
            val_old[i] = mem_rdata_compute[i*ACC_WIDTH +: ACC_WIDTH];
            val_new[i] = p1_mxu_data[i*ACC_WIDTH +: ACC_WIDTH];

            // 2. Add
            val_sum[i] = val_old[i] + val_new[i];

            // 3. Mux (Overwrite vs Accumulate)
            val_result[i] = p1_accumulate_en ? val_sum[i] : val_new[i];

            // 4. Pack using Indexed Part-Select
            write_data_comb[i*ACC_WIDTH +: ACC_WIDTH] = val_result[i];
        end
    end

    // -------------------------------------------------------------------------
    // 3. Pipeline Registers & Compute Port Write (Stage 1)
    // -------------------------------------------------------------------------
    always_ff @(posedge clk) begin
        if (reset) begin
            p1_valid         <= 1'b0;
            p1_accumulate_en <= 1'b0;
            p1_write_addr    <= '0;
            p1_mxu_data      <= '0;
        end else begin
            // Pipeline Stage 0 -> 1
            p1_valid         <= valid_in;
            p1_accumulate_en <= accumulate_en;
            p1_write_addr    <= write_row_addr;
            p1_mxu_data      <= mxu_data_in;

            // Write to memory
            if (p1_valid) begin
                mem[p1_write_addr] <= write_data_comb;
            end
        end
    end

    // -------------------------------------------------------------------------
    // 4. Drain Port Read (Read Only) - ISOLATED BLOCK
    // -------------------------------------------------------------------------
    // Separate block ensures clean dual-port RAM inference.
    always_ff @(posedge clk) begin
        if (reset)
            drain_data_out <= '0;
        else
            drain_data_out <= mem[drain_read_addr];
    end

endmodule

`timescale 1ns/1ps
`default_nettype none

module pe #(
    parameter integer D_WIDTH = 8,
    parameter integer ACC_WIDTH = 32
)(
    input  logic clk,
    input  logic reset,

    // Mode Control
    input  logic weight_en,                 // 1 = Shift Weights, 0 = Compute

    // Vertical Data Paths
    input  logic [D_WIDTH-1:0]   w_in_n,    // Weight In (North)
    output logic [D_WIDTH-1:0]   w_out_s,   // Weight Out (South)

    // CHANGE: Activations are now UNSIGNED (no 'signed' keyword)
    input  logic [D_WIDTH-1:0]   act_in_n,  // Activation In (North)
    output logic [D_WIDTH-1:0]   act_out_s, // Activation Out (South)

    // Horizontal Data Path
    input  logic signed [ACC_WIDTH-1:0] psum_in_w, // Partial Sum In (West)
    output logic signed [ACC_WIDTH-1:0] psum_out_e // Partial Sum Out (East)
);

    // -------------------------------------------------------------------------
    // Internal State
    // -------------------------------------------------------------------------

    // Weight Storage (Remains Signed)
    logic signed [D_WIDTH-1:0] weight_reg;

    // Output Registers
    logic [D_WIDTH-1:0]   act_reg;      // Unsigned storage
    logic signed [ACC_WIDTH-1:0] psum_reg;

    // -------------------------------------------------------------------------
    // Logic Implementation
    // -------------------------------------------------------------------------

    always_ff @(posedge clk) begin
        if (reset) begin
            weight_reg <= '0;
            act_reg    <= '0;
            psum_reg   <= '0;
        end else begin
            // 1. Weight Path Logic
            if (weight_en) begin
                weight_reg <= $signed(w_in_n);
            end 

            // 2. Activation Path Logic (Pass through)
            act_reg <= act_in_n;

            // 3. Partial Sum / MAC Logic
            if (weight_en) begin
                psum_reg <= '0; 
            end else begin
                // MIXED PRECISION MATH:
                // We cast Unsigned Act (8-bit) to Signed (9-bit) by prepending 0.
                // Weight is already Signed (8-bit).
                // 9-bit * 8-bit = 17-bit Signed Result.

                logic signed [D_WIDTH:0] act_9bit;
                act_9bit = {1'b0, act_in_n}; // e.g. 255 (0xFF) becomes 0_1111_1111 (+255)

                psum_reg <= psum_in_w + (act_9bit * weight_reg);
            end
        end
    end

    // -------------------------------------------------------------------------
    // Output Assignments
    // -------------------------------------------------------------------------

    // Cast weight back to bits for output wire
    assign w_out_s    = weight_reg; 
    assign act_out_s  = act_reg;
    assign psum_out_e = psum_reg;

endmodule

