`timescale 1ns/1ps
`default_nettype none

module post_processor #(
    parameter integer ARRAY_SIZE = 16
)(
    input  logic clk,
    input  logic reset,

    // --- Configuration ---
    input  logic signed [31:0] quant_mult,
    input  logic        [7:0]  quant_shift,
    input  logic        [7:0]  zero_point,
    input  logic               relu_en,
    // input logic output_signed, // REMOVED: Not driven by tpu_top

    // --- Bias Loading Interface ---
    input  logic bias_wr_en,
    input  logic [$clog2(ARRAY_SIZE)-1:0] bias_wr_addr,
    input  logic signed [31:0] bias_wr_data,

    // --- Data Stream Interface ---
    input  logic valid_in,
    input  logic [ARRAY_SIZE*32-1:0] acc_data_in,

    // --- Output to Result Writer ---
    output logic valid_out,
    output logic [ARRAY_SIZE*8-1:0]  packed_out
);

    // -------------------------------------------------------------------------
    // Internal Memory: Bias Storage
    // -------------------------------------------------------------------------
    logic signed [31:0] bias_mem [0:ARRAY_SIZE-1];

    always_ff @(posedge clk) begin
        if (bias_wr_en) begin
            bias_mem[bias_wr_addr] <= bias_wr_data;
        end
    end

    // -------------------------------------------------------------------------
    // Pipeline Stage 1: Bias Addition
    // -------------------------------------------------------------------------
    logic        p1_valid;
    logic signed [31:0] p1_sum [ARRAY_SIZE-1:0];

    // Unpack input vector
    wire signed [31:0] acc_unpacked [ARRAY_SIZE-1:0];
    genvar u;
    generate
        for (u = 0; u < ARRAY_SIZE; u++) begin : unpack_in
            assign acc_unpacked[u] = acc_data_in[u*32 +: 32];
        end
    endgenerate

    integer k;
    always_ff @(posedge clk) begin
        if (reset) p1_valid <= 0;
        else       p1_valid <= valid_in;

        for (k = 0; k < ARRAY_SIZE; k++) begin
            if (valid_in) begin
                p1_sum[k] <= acc_unpacked[k] + bias_mem[k];
            end
        end
    end

    // -------------------------------------------------------------------------
    // Pipeline Stage 2: Quantization & Saturation
    // -------------------------------------------------------------------------
    logic       p2_valid;
    logic [7:0] p2_out [ARRAY_SIZE-1:0];

    always_ff @(posedge clk) begin
        if (reset) p2_valid <= 0;
        else       p2_valid <= p1_valid;
    end

    genvar i;
    generate
        for (i = 0; i < ARRAY_SIZE; i = i + 1) begin : lane_logic

            // 1. Math
            wire signed [63:0] product;
            wire signed [63:0] shifted;
            wire signed [63:0] final_val;

            assign product   = p1_sum[i] * $signed(quant_mult);
            assign shifted   = product >>> quant_shift;
            assign final_val = shifted + $signed({56'd0, zero_point});

            // 2. Saturation (Wires for Icarus compatibility)
            // A. ReLU
            wire signed [63:0] val_relu = (relu_en && final_val < 0) ? 64'sd0 : final_val;

            // B. Unsigned Clamp (0 to 255)
            // This is the ONLY mode we support now, matching tpu_top.sv
            wire [7:0] val_final_byte = (val_relu < 0) ? 8'd0 :
                                        (val_relu > 255) ? 8'd255 :
                                        val_relu[7:0];

            // 3. Pipeline Register
            always_ff @(posedge clk) begin
                if (p1_valid) begin
                    p2_out[i] <= val_final_byte;
                end
            end
        end
    endgenerate

    // -------------------------------------------------------------------------
    // Output Packing
    // -------------------------------------------------------------------------
    genvar j;
    generate
        for (j = 0; j < ARRAY_SIZE; j++) begin : pack
            assign packed_out[j*8 +: 8] = p2_out[j];
        end
    endgenerate

    assign valid_out = p2_valid;

endmodule

