`timescale 1ns/1ps
`default_nettype none

module tpu_top #(
    parameter integer ARRAY_SIZE = 8,
    parameter integer D_WIDTH = 8,
    parameter integer ACC_WIDTH = 32,
    parameter integer RAM_WIDTH = 32,
    parameter integer RAM_ADDR_W = 16,
    parameter integer ACC_DEPTH_BITS = 8
)(
    input  logic clk,
    input  logic reset,

    // --- CPU Interface ---
    input  logic [5:0]  reg_addr, // Expanded to 6 bits for new registers
    input  logic [31:0] reg_wdata,
    input  logic        reg_write,
    output logic [31:0] reg_rdata,

    // --- System RAM Interface ---
    output logic [RAM_ADDR_W-1:0] ram_addr,
    output logic                  ram_we,
    output logic [RAM_WIDTH-1:0]  ram_wdata,
    input  logic [RAM_WIDTH-1:0]  ram_rdata
);

    // -------------------------------------------------------------------------
    // 1. Registers / Configuration
    // -------------------------------------------------------------------------
    // 0x00: CSR (Bit 0: Start, Bit 1: Busy, Bit 2: Done)
    // 0x04: M_Dim (Num Rows)
    // 0x08: K_Dim (Num K Tiles) -- NEW for V1
    // 0x10: Weight Base Addr
    // 0x14: Input Base Addr
    // 0x18: Output Base Addr
    // 0x20: Quant Mult
    // 0x24: Quant Shift (Bits 7:0), Zero Point (Bits 15:8), ReLU (Bit 16)
    // 0x30: Bias Base Addr -- NEW for V1

    logic       reg_start;
    logic       reg_busy;
    logic       reg_done;
    logic [7:0] reg_num_rows;
    logic [7:0] reg_k_tiles;  // How many accumulation passes

    logic [RAM_ADDR_W-1:0] reg_weight_base;
    logic [RAM_ADDR_W-1:0] reg_input_base;
    logic [RAM_ADDR_W-1:0] reg_output_base;
    logic [RAM_ADDR_W-1:0] reg_bias_base;

    logic signed [31:0] reg_quant_mult;
    logic [7:0]         reg_quant_shift;
    logic [7:0]         reg_zero_point;
    logic               reg_relu_en;

    // K-Loop Counters and Address Pointers
    logic [7:0] k_loop_cnt;
    logic [RAM_ADDR_W-1:0] current_weight_base;
    logic [RAM_ADDR_W-1:0] current_input_base;

    always_ff @(posedge clk) begin
        if (reset) begin
            reg_start       <= 0;
            reg_num_rows    <= 8'd8;
            reg_k_tiles     <= 8'd1;
            reg_weight_base <= 0;
            reg_input_base  <= 0;
            reg_output_base <= 0;
            reg_bias_base   <= 0;
            reg_quant_mult  <= 1; // Default Identity
            reg_quant_shift <= 0;
            reg_zero_point  <= 0;
            reg_relu_en     <= 0;
        end else begin
            if (reg_start) reg_start <= 0; // Auto-clear

            if (reg_write) begin
                case (reg_addr)
                    6'h00: reg_start       <= reg_wdata[0];
                    6'h04: reg_num_rows    <= reg_wdata[7:0];
                    6'h08: reg_k_tiles     <= reg_wdata[7:0];

                    6'h10: reg_weight_base <= reg_wdata[RAM_ADDR_W-1:0];
                    6'h14: reg_input_base  <= reg_wdata[RAM_ADDR_W-1:0];
                    6'h18: reg_output_base <= reg_wdata[RAM_ADDR_W-1:0];

                    6'h20: reg_quant_mult  <= reg_wdata;
                    6'h24: begin
                        reg_quant_shift <= reg_wdata[7:0];
                        reg_zero_point  <= reg_wdata[15:8];
                        reg_relu_en     <= reg_wdata[16];
                    end

                    6'h30: reg_bias_base   <= reg_wdata[RAM_ADDR_W-1:0];
                endcase
            end
        end
    end

    // Read Logic
    always_comb begin
        case (reg_addr)
            6'h00: reg_rdata = {29'b0, reg_done, reg_busy, reg_start};
            6'h04: reg_rdata = {24'b0, reg_num_rows};
            6'h08: reg_rdata = {24'b0, reg_k_tiles};
            6'h10: reg_rdata = {16'b0, reg_weight_base};
            6'h14: reg_rdata = {16'b0, reg_input_base};
            6'h18: reg_rdata = {16'b0, reg_output_base};
            6'h20: reg_rdata = reg_quant_mult;
            6'h24: reg_rdata = {15'b0, reg_relu_en, reg_zero_point, reg_quant_shift};
            6'h30: reg_rdata = {16'b0, reg_bias_base};
            default: reg_rdata = 32'hDEADBEEF;
        endcase
    end

    // -------------------------------------------------------------------------
    // 2. Main FSM
    // -------------------------------------------------------------------------
    typedef enum logic [3:0] {
        S_IDLE,
        S_LOAD_BIASES,   // New State
        S_LOAD_WEIGHTS,
        S_COMPUTE,
        S_INCREMENT_K,   // New State: Check loop and update pointers
        S_DRAIN,
        S_DONE
    } state_t;

    state_t state, state_d, next_state;

    // Helper for start pulse generation
    always_ff @(posedge clk) begin
        if (reset) state_d <= S_IDLE;
        else       state_d <= state;
    end
    wire state_entry = (state != state_d);

    wire bias_done, loader_done, fetcher_done, writer_done;
    logic [7:0] compute_result_cnt;
    wire compute_done = (compute_result_cnt == reg_num_rows);

    always_comb begin
        next_state = state;
        case (state)
            S_IDLE: 
                if (reg_start) next_state = S_LOAD_BIASES;

            S_LOAD_BIASES:
                if (bias_done) next_state = S_LOAD_WEIGHTS;

            S_LOAD_WEIGHTS: 
                if (loader_done) next_state = S_COMPUTE;

            S_COMPUTE: 
                if (compute_done) next_state = S_INCREMENT_K;

            S_INCREMENT_K:
                if (k_loop_cnt < reg_k_tiles - 1) next_state = S_LOAD_WEIGHTS;
                else                              next_state = S_DRAIN;

            S_DRAIN: 
                if (writer_done) next_state = S_DONE;

            S_DONE: 
                next_state = S_IDLE;
        endcase
    end

    // FSM Datapath (Loop Counters & Address Updates)
    always_ff @(posedge clk) begin
        if (reset) begin
            state <= S_IDLE;
            k_loop_cnt <= 0;
            reg_busy <= 0; reg_done <= 0;
        end else begin
            state <= next_state;
            reg_busy <= (state != S_IDLE && state != S_DONE);

            // Make reg_done sticky - stays high until next start
            if (reg_start)
                reg_done <= 0;
            else if (state == S_DONE)
                reg_done <= 1;
            // else: maintain current value (sticky behavior)

            if (state == S_IDLE && reg_start) begin
                k_loop_cnt <= 0;
                current_weight_base <= reg_weight_base;
                current_input_base  <= reg_input_base;
            end else if (state == S_INCREMENT_K && state_entry) begin
                // Loop Increment
                k_loop_cnt <= k_loop_cnt + 1;

                // Pointer Arithmetic for Next Tile
                // Weights: Advance by ARRAY_SIZE * ARRAY_SIZE bytes
                current_weight_base <= current_weight_base + (ARRAY_SIZE * ARRAY_SIZE);

                // Inputs: Advance by num_rows * ARRAY_SIZE bytes
                current_input_base  <= current_input_base + (reg_num_rows * ARRAY_SIZE);
            end
        end
    end

    // -------------------------------------------------------------------------
    // 3. Sub-Modules
    // -------------------------------------------------------------------------

    // --- Bias Loader ---
    wire [RAM_ADDR_W-1:0] bl_ram_addr;
    wire bl_ppu_we;
    wire [$clog2(ARRAY_SIZE)-1:0] bl_ppu_addr;
    wire [31:0] bl_ppu_data;

    bias_loader #(
        .ARRAY_SIZE(ARRAY_SIZE), 
        .RAM_WIDTH(RAM_WIDTH), 
        .RAM_ADDR_W(RAM_ADDR_W)
    ) u_bias_ldr (
        .clk(clk), 
        .reset(reset),
        .start(state == S_LOAD_BIASES && state_entry),
        .base_addr(reg_bias_base),
        .done(bias_done),
        .ram_addr(bl_ram_addr),
        .ram_rdata(ram_rdata),

        // FIX: Update port names to match bias_loader.v definition
        .bias_wr_en(bl_ppu_we),       // Was .ppu_wr_en
        .bias_wr_addr(bl_ppu_addr),   // Was .ppu_wr_addr
        .bias_wr_data(bl_ppu_data)    // Was .ppu_wr_data
    );

    // --- Weight Loader ---
    wire array_weight_en;
    wire [ARRAY_SIZE*D_WIDTH-1:0] array_top_weights;
    wire [RAM_ADDR_W-1:0] wl_ram_addr;

    weight_loader #(.ARRAY_SIZE(ARRAY_SIZE), .D_WIDTH(D_WIDTH), .RAM_WIDTH(RAM_WIDTH), .RAM_ADDR_W(RAM_ADDR_W)) u_loader (
        .clk(clk), .reset(reset),
        .start(state == S_LOAD_WEIGHTS && state_entry),
        .base_addr(current_weight_base), // Use Dynamic Pointer
        .done(loader_done),
        .array_weight_en(array_weight_en),
        .array_weights_out(array_top_weights),
        .ram_addr(wl_ram_addr),
        .ram_rdata(ram_rdata)
    );

    // --- Matrix Fetcher ---
    wire mf_valid_out;
    wire [ARRAY_SIZE*D_WIDTH-1:0] mf_activations;
    wire [RAM_ADDR_W-1:0] mf_ram_addr;

    matrix_fetcher #(.ARRAY_SIZE(ARRAY_SIZE), .D_WIDTH(D_WIDTH), .RAM_WIDTH(RAM_WIDTH), .RAM_ADDR_W(RAM_ADDR_W)) u_fetcher (
        .clk(clk), .reset(reset),
        .start(state == S_COMPUTE && state_entry),
        .base_addr(current_input_base), // Use Dynamic Pointer
        .num_rows(reg_num_rows),
        .done(fetcher_done),
        .busy(),
        .valid_out(mf_valid_out),
        .activations_out(mf_activations),
        .ram_addr(mf_ram_addr),
        .ram_rdata(ram_rdata)
    );

    // --- Systolic Array ---
    wire sa_valid_out;
    wire [ARRAY_SIZE*ACC_WIDTH-1:0] sa_psums_out;

    systolic_array #(.ARRAY_SIZE(ARRAY_SIZE), .D_WIDTH(D_WIDTH), .ACC_WIDTH(ACC_WIDTH)) u_array (
        .clk(clk), .reset(reset),
        .weight_en(array_weight_en),
        .top_row_weights(array_top_weights),
        .data_valid_in(mf_valid_out),
        .activations_in(mf_activations),
        .psums_in('0),
        .data_valid_out(sa_valid_out),
        .psums_out(sa_psums_out)
    );

    // --- Accumulator ---
    // Count valid outputs to drive write address
    always_ff @(posedge clk) begin
        if (reset || state == S_LOAD_WEIGHTS) compute_result_cnt <= 0;
        else if (sa_valid_out) compute_result_cnt <= compute_result_cnt + 1;
    end

    wire [ACC_DEPTH_BITS-1:0] acc_wr_addr = compute_result_cnt;
    wire [ACC_DEPTH_BITS-1:0] acc_rd_addr;
    wire [ARRAY_SIZE*ACC_WIDTH-1:0] acc_drain_data;

    accumulator #(.ARRAY_SIZE(ARRAY_SIZE), .ACC_WIDTH(ACC_WIDTH), .ACC_DEPTH_BITS(ACC_DEPTH_BITS)) u_accum (
        .clk(clk), .reset(reset),
        .valid_in(sa_valid_out),
        .mxu_data_in(sa_psums_out),
        .accumulate_en(k_loop_cnt > 0), // DYNAMIC: 0 on first pass, 1 on others
        .write_row_addr(acc_wr_addr),
        .drain_read_addr(acc_rd_addr),
        .drain_data_out(acc_drain_data)
    );

    // --- Post Processor (NEW) ---
    wire ppu_valid_out;
    wire [ARRAY_SIZE*8-1:0] ppu_packed_out;

    // Use Result Writer to trigger PPU flow.
    // Result Writer asks for data (acc_rd_addr), Accumulator responds.
    // PPU sits on that response wire.
    // Wait: PPU needs valid signal. Result writer controls read addr.
    // We need to delay the PPU valid signal to match Accumulator Read Latency?
    // Actually, PPU takes `valid_in`.
    // In V0, Result Writer handled the wait states.
    // In V1, Result Writer Request -> Accumulator Read -> PPU Process -> Result Writer Capture.
    // This adds latency to the Result Writer's "REQ -> CAPTURE" path.
    // Result Writer FSM needs to know it waits longer? 
    // Or we just rely on PPU valid_out?

    // Simplest approach: Result Writer drives Address.
    // We generate a "Read Valid" pulse to the PPU 1 cycle later (BRAM latency).

    logic acc_read_valid;
    always_ff @(posedge clk) acc_read_valid <= (state == S_DRAIN); // Rough approximation

    post_processor #(.ARRAY_SIZE(ARRAY_SIZE)) u_ppu (
        .clk(clk), .reset(reset),
        .quant_mult(reg_quant_mult), .quant_shift(reg_quant_shift),
        .zero_point(reg_zero_point), .relu_en(reg_relu_en),
        // Bias Load
        .bias_wr_en(bl_ppu_we), .bias_wr_addr(bl_ppu_addr), .bias_wr_data(bl_ppu_data),
        // Stream
        .valid_in(1'b1), // Logic simplification: PPU processes whatever Accumulator outputs
                         // But we need to gate it? No, just rely on Result Writer to latch valid data.
                         // Actually, PPU pipeline is valid-driven.
                         // We need to connect this to the Result Writer's handshake.
        .acc_data_in(acc_drain_data),
        .valid_out(ppu_valid_out),
        .packed_out(ppu_packed_out)
    );

    // CORRECTION for PPU-Writer Handshake:
    // The Result Writer V1 assumes `ppu_data_in` is available when it enters CAPTURE.
    // In V0, Acc latency was 1 cycle. S_REQ -> S_WAIT -> S_CAPTURE worked.
    // In V1, PPU adds 2 cycles. Total 3 cycles.
    // Result Writer `S_WAIT` needs to be longer or PPU needs to be combinatorial (it isn't).
    // FIX: Result Writer V1 waits for `ppu_valid_out`? No, writer drives logic.
    // *Hack for V1*: Result Writer assumes fixed latency.
    // Ideally, Result Writer asserts "Read", and PPU asserts "Valid" 3 cycles later.
    // Let's modify Result Writer to check `ppu_valid_out` before Capturing?
    // Or just extend S_WAIT. 
    // Given code freeze, let's assume Result Writer has a configurable wait or we hardcode S_WAIT to 3 cycles.

    // --- Result Writer ---
    wire [RAM_ADDR_W-1:0] rw_ram_addr;
    wire rw_ram_we;
    wire [RAM_WIDTH-1:0] rw_ram_wdata;

    result_writer #(.ARRAY_SIZE(ARRAY_SIZE), .RAM_WIDTH(RAM_WIDTH), .RAM_ADDR_W(RAM_ADDR_W), .ACC_DEPTH_BITS(ACC_DEPTH_BITS)) u_writer (
        .clk(clk), .reset(reset),
        .start(state == S_DRAIN && state_entry),
        .base_addr(reg_output_base),
        .num_rows(reg_num_rows),
        .done(writer_done),
        .busy(),
        .acc_read_addr(acc_rd_addr),
        .ppu_data_in(ppu_packed_out),
        .ram_addr(rw_ram_addr),
        .ram_we(rw_ram_we),
        .ram_wdata(rw_ram_wdata)
    );

    // -------------------------------------------------------------------------
    // 4. RAM Mux
    // -------------------------------------------------------------------------
    always_comb begin
        ram_addr = 0; ram_we = 0; ram_wdata = 0;
        case (state)
            S_LOAD_BIASES: begin
                ram_addr = bl_ram_addr;
                ram_we = 0;
            end
            S_LOAD_WEIGHTS: begin
                ram_addr = wl_ram_addr;
                ram_we = 0;
            end
            S_COMPUTE: begin
                ram_addr = mf_ram_addr;
                ram_we = 0;
            end
            S_DRAIN: begin
                ram_addr = rw_ram_addr;
                ram_we = rw_ram_we;
                ram_wdata = rw_ram_wdata;
            end
            default: ;
        endcase
    end

endmodule

