    // Signals
    // -------------------------------------------------------------------------
    logic clk;
    logic reset;

    logic valid_in;
    logic [ARRAY_SIZE*ACC_WIDTH-1:0] mxu_data_in;
    logic accumulate_en;
    logic [ACC_DEPTH_BITS-1:0] write_row_addr;

    logic [ACC_DEPTH_BITS-1:0] drain_read_addr;
    wire  [ARRAY_SIZE*ACC_WIDTH-1:0] drain_data_out;

    // Helper to unpack output
    logic [ACC_WIDTH-1:0] debug_drain_row [ARRAY_SIZE-1:0];
    genvar i;
    generate
        for (i=0; i<ARRAY_SIZE; i++) 
            assign debug_drain_row[i] = drain_data_out[(i+1)*ACC_WIDTH-1 : i*ACC_WIDTH];
    endgenerate

    // -------------------------------------------------------------------------
    // DUT
    // -------------------------------------------------------------------------
    accumulator #(
        .ARRAY_SIZE(ARRAY_SIZE),
        .ACC_WIDTH(ACC_WIDTH),
        .ACC_DEPTH_BITS(ACC_DEPTH_BITS)
    ) dut (
        .clk(clk),
        .reset(reset),
        .valid_in(valid_in),
        .mxu_data_in(mxu_data_in),
        .accumulate_en(accumulate_en),
        .write_row_addr(write_row_addr),
        .drain_read_addr(drain_read_addr),
        .drain_data_out(drain_data_out)
    );

    // -------------------------------------------------------------------------
    // Clock
    // -------------------------------------------------------------------------
    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end

    // -------------------------------------------------------------------------
    // Test Procedure
    // -------------------------------------------------------------------------
    initial begin
        `WAVE_INIT(tb_accumulator)

        // Init
        reset = 1;
        valid_in = 0;
        accumulate_en = 0;
        write_row_addr = 0;
        drain_read_addr = 0;
        mxu_data_in = 0;

        @(negedge clk);
        reset = 0;

        // ---------------------------------------------------------------------
        // Test 1: The Basic Overwrite (First Tile)
        // ---------------------------------------------------------------------
        print_test_header(1, "Basic Overwrite (Store Mode)");

        // Drive Inputs: Addr=10, Data=100 (for all rows to simplify)
        @(posedge clk);
        accumulate_en <= 0; // Overwrite
        valid_in <= 1;
        write_row_addr <= 4'd10;
        // Construct vector where all rows = 100
        mxu_data_in <= {ARRAY_SIZE{32'd100}};

        // Stop Driving
        @(posedge clk);
        valid_in <= 0;
        mxu_data_in <= 0;

        // Wait for Pipeline (Read + Write)
        // Write happens at T+1 relative to input. 
        // Sync Read for drain takes T+1.
        repeat(3) @(posedge clk);

        // Read Back
        drain_read_addr <= 4'd10;
        @(posedge clk); // Clock latch addr
        #1; // Wait for data valid

        assert_equal(debug_drain_row[0], 32'd100, "Addr 10 contains 100 (Row 0)");
        assert_equal(debug_drain_row[3], 32'd100, "Addr 10 contains 100 (Row 3)");


        // ---------------------------------------------------------------------
        // Test 2: The Accumulation (Second Tile)
        // ---------------------------------------------------------------------
        print_test_header(2, "Accumulation (Read-Modify-Write)");

        // Add 50 to existing 100 at Addr 10
        @(posedge clk);
        accumulate_en <= 1; // Accumulate!
        valid_in <= 1;
        write_row_addr <= 4'd10;
        mxu_data_in <= {ARRAY_SIZE{32'd50}};

        @(posedge clk);
        valid_in <= 0;

        // Wait pipeline
        repeat(3) @(posedge clk);

        // Read Back
        drain_read_addr <= 4'd10;
        @(posedge clk);
        #1;

        assert_equal(debug_drain_row[0], 32'd150, "Addr 10: 100 + 50 = 150");


        // ---------------------------------------------------------------------
        // Test 3: The Burst Hazard (Throughput)
        // ---------------------------------------------------------------------
        print_test_header(3, "Burst Hazard: Back-to-Back Writes");

        // Setup: Overwrite mode
        accumulate_en <= 0;

        // Cycle T: Write Row 0 with 0xAA
        @(posedge clk);
        valid_in <= 1;
        write_row_addr <= 4'd0;
        mxu_data_in <= {ARRAY_SIZE{32'hAA}};

        // Cycle T+1: Write Row 1 with 0xBB
        @(posedge clk);
        valid_in <= 1;
        write_row_addr <= 4'd1;
        mxu_data_in <= {ARRAY_SIZE{32'hBB}};

        // Stop
        @(posedge clk);
        valid_in <= 0;

        // Wait pipeline
        repeat(3) @(posedge clk);

        // Check Row 0
        drain_read_addr <= 4'd0;
        @(posedge clk); #1;
        assert_equal(debug_drain_row[0], 32'hAA, "Row 0 stored 0xAA");

        // Check Row 1
        drain_read_addr <= 4'd1;
        @(posedge clk); #1;
        assert_equal(debug_drain_row[0], 32'hBB, "Row 1 stored 0xBB");

        $finish;
    end

endmodule

