module tb_input_skewer;

    parameter ARRAY_SIZE = 4;
    parameter D_WIDTH = 8;

    logic clk;
    logic reset;
    logic [ARRAY_SIZE*D_WIDTH-1:0] flat_in;
    wire  [ARRAY_SIZE*D_WIDTH-1:0] skewed_out;

    logic [D_WIDTH-1:0] debug_row_out [ARRAY_SIZE-1:0];

    input_skewer #(
        .ARRAY_SIZE(ARRAY_SIZE),
        .D_WIDTH(D_WIDTH)
    ) dut (
        .clk(clk),
        .reset(reset),
        .flat_in(flat_in),
        .skewed_out(skewed_out)
    );

    genvar i;
    generate
        for (i = 0; i < ARRAY_SIZE; i++) begin
            assign debug_row_out[i] = skewed_out[(i+1)*D_WIDTH-1 : i*D_WIDTH];
        end
    endgenerate

    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end

    initial begin
        `WAVE_INIT(tb_input_skewer)

