        flat_in = '0;

        @(negedge clk);
        reset = 0;

        print_section("Pipeline Flush");
        repeat(ARRAY_SIZE + 2) @(posedge clk);

        // ---------------------------------------------------------------------
        // Test Case 1: The Diagonal Walk (Synchronous Drive)
        // ---------------------------------------------------------------------
        print_test_header(1, "The Diagonal Walk: Synchronous Skew Verification");

        // Action: Drive Impulse (All 0xFF) AT the clock edge (Synchronous Source)
        @(posedge clk);
        flat_in <= {ARRAY_SIZE{8'hFF}}; // Non-blocking: simulates upstream reg update

        // Check T+0 (Immediate post-edge)
        // Row 0 (Wire) should see the NEW value immediately (combinatorial path matches upstream)
        // Row 1 (Reg) should capture the OLD value (0x00)
        @(negedge clk); // Check safely away from edge race
        assert_equal(debug_row_out[0], 8'hFF, "Cycle 0: Row 0 (Wire) sees New Data");
        assert_equal(debug_row_out[1], 8'h00, "Cycle 0: Row 1 (Reg) still outputs Old Data");

        // Action: Drive 0x00 at T+1
        @(posedge clk);
        flat_in <= {ARRAY_SIZE{8'h00}};

        // Check T+1
        // Row 0 (Wire) sees NEW (00)
        // Row 1 (Reg) outputs what was captured at T0 (FF) -> The delayed packet!
        @(negedge clk);
        assert_equal(debug_row_out[0], 8'h00, "Cycle 1: Row 0 sees New Data (00)");
        assert_equal(debug_row_out[1], 8'hFF, "Cycle 1: Row 1 outputs delayed Data (FF)");
        assert_equal(debug_row_out[2], 8'h00, "Cycle 1: Row 2 still outputs Old Data");

        // Check T+2
        @(posedge clk);
        @(negedge clk);
        assert_equal(debug_row_out[2], 8'hFF, "Cycle 2: Row 2 outputs delayed Data (FF)");

        // ---------------------------------------------------------------------
        // Test Case 2: The Pipeline Stress
        // ---------------------------------------------------------------------
        print_test_header(2, "The Pipeline Stress");

        // Reset to clean state
        flat_in <= '0;
        repeat(2) @(posedge clk);

        // Drive AA at T0, BB at T1
        @(posedge clk);
        flat_in <= {ARRAY_SIZE{8'hAA}};

        @(posedge clk);
        flat_in <= {ARRAY_SIZE{8'hBB}};

        // Check T1 (Post second edge)
        // Row 1 should be outputting AA (Captured at T0)
        @(negedge clk);
        assert_equal(debug_row_out[1], 8'hAA, "Row 1 outputs AA (delayed 1 cycle)");

        // Check T2
        @(posedge clk);
        flat_in <= '0;
        @(negedge clk);
        assert_equal(debug_row_out[1], 8'hBB, "Row 1 outputs BB (delayed 1 cycle)");

        $finish;
    end

endmodule

