    wire busy;
    wire valid_out;
    wire [ARRAY_SIZE*D_WIDTH-1:0] activations_out;

    wire [RAM_ADDR_W-1:0] ram_addr;
    logic [RAM_WIDTH-1:0] ram_rdata;

    // -------------------------------------------------------------------------
    // DUT
    // -------------------------------------------------------------------------
    matrix_fetcher #(
        .ARRAY_SIZE(ARRAY_SIZE),
        .D_WIDTH(D_WIDTH),
        .RAM_WIDTH(RAM_WIDTH),
