        .ram_addr(ram_addr),
        .ram_rdata(ram_rdata)
    );

    // -------------------------------------------------------------------------
    // Mock RAM
    // -------------------------------------------------------------------------
    // Latency = 1 Cycle
    // Specific values for Test 1
