        if (ram_addr == 12'h100)      ram_rdata <= 16'h00AA;
        else if (ram_addr == 12'h104) ram_rdata <= 16'h00BB; // +4 for byte addr
        else                          ram_rdata <= {4'h0, ram_addr}; // Fallback
    end

    // -------------------------------------------------------------------------
    // Clock
    // -------------------------------------------------------------------------
    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end

    // -------------------------------------------------------------------------
    // Test Procedure
    // -------------------------------------------------------------------------
    initial begin
        `WAVE_INIT(tb_matrix_fetcher)

        reset = 1;
        start = 0;
        base_addr = 0;
        num_rows = 0;

        @(negedge clk);
        reset = 0;

        // ---------------------------------------------------------------------
        // Test 1: The Packing & Alignment Check
        // ---------------------------------------------------------------------
        print_test_header(1, "Packing Check (2 Reads -> 1 Vector)");

        // Setup for 1 Row
        base_addr = 12'h100;
        num_rows = 8'd1;

        @(posedge clk);
        start = 1;
        @(posedge clk);
        start = 0;

        // Wait for valid_out
        wait(valid_out);
        @(negedge clk); // Check falling edge of validity window

        // Expectation:
        // Read 1 (LSB): 0x00AA
        // Read 2 (MSB): 0x00BB
        // Result: 0x00BB00AA
        assert_equal(activations_out, 32'h00BB00AA, "Vector Packed Little Endian");

        wait(done);
        @(negedge clk);
        assert_equal(busy, 1'b0, "Module not busy after done");


        // ---------------------------------------------------------------------
        // Test 2: The Multi-Row Stream
        // ---------------------------------------------------------------------
        print_test_header(2, "Streaming 3 Rows");

        base_addr = 12'h200; // New Area
        num_rows = 8'd3;

        @(posedge clk);
        start = 1;
        @(posedge clk);
        start = 0;

        // Count output pulses
        // We can't use 'wait' easily for counting in a linear block, 
        // so we just rely on timing or separate spy block.
        // Let's verify DONE fires eventually.

        wait(done);
        @(negedge clk);
        assert_equal(done, 1'b1, "Stream Finished 3 Rows");

        $finish;
    end

    // -------------------------------------------------------------------------
    // Signal Spy
    // -------------------------------------------------------------------------
    integer pulse_count = 0;
    always @(posedge clk) begin
        if (valid_out) begin
            pulse_count <= pulse_count + 1;
            $display("  [TB] Output Valid: %h", activations_out);
        end

        // Reset count on start
        if (start) pulse_count <= 0;
    end

