module tb_post_processor;

    parameter ARRAY_SIZE = 4;
    localparam ADDR_WIDTH = $clog2(ARRAY_SIZE);

    logic clk, reset;

    // Config
    logic signed [31:0] quant_mult;
    logic [7:0]  quant_shift;
    logic [7:0]  zero_point;
    logic        relu_en;

    // Bias Write Interface
    logic bias_wr_en;
    logic [ADDR_WIDTH-1:0] bias_wr_addr;
    logic signed [31:0] bias_wr_data;

    // Stream
    logic valid_in;
    logic [ARRAY_SIZE*32-1:0] acc_data_in;
    wire  valid_out;
    wire  [ARRAY_SIZE*8-1:0]  packed_out;

    logic [7:0] out_bytes [ARRAY_SIZE-1:0];
    genvar k;
    generate
        for(k=0; k<ARRAY_SIZE; k++) assign out_bytes[k] = packed_out[(k+1)*8-1 : k*8];
    endgenerate

    post_processor #(.ARRAY_SIZE(ARRAY_SIZE)) dut (.*);

    initial begin
        clk = 0; forever #5 clk = ~clk;
    end

    // Helper task to load biases serially
    task load_biases(input logic [31:0] b0, input logic [31:0] b1, input logic [31:0] b2, input logic [31:0] b3);
        begin
            // Cycle 0
            @(posedge clk); 
            bias_wr_en <= 1; bias_wr_addr <= 0; bias_wr_data <= b0;

            // Cycle 1
            @(posedge clk); 
            bias_wr_en <= 1; bias_wr_addr <= 1; bias_wr_data <= b1;

            // Cycle 2
            @(posedge clk); 
            bias_wr_en <= 1; bias_wr_addr <= 2; bias_wr_data <= b2;

            // Cycle 3
            @(posedge clk); 
            bias_wr_en <= 1; bias_wr_addr <= 3; bias_wr_data <= b3;

            // Cycle 4 (Turn off)
            @(posedge clk); 
            bias_wr_en <= 0;
            // Wait one cycle to ensure write completes before using data
            @(posedge clk);
        end
    endtask

    initial begin
        `WAVE_INIT(tb_post_processor)

        reset = 1; 
        quant_mult = 1; quant_shift = 0; zero_point = 0; relu_en = 0;
        bias_wr_en = 0; bias_wr_addr = 0; bias_wr_data = 0;
        valid_in = 0; acc_data_in = 0;

        @(negedge clk) reset = 0;

        // ---------------------------------------------------------
        // Test 1: Passthrough & Bias
        // ---------------------------------------------------------
        print_test_header(1, "Passthrough & Bias");

        // Load Biases: {0, 5, 10, 100}
        load_biases(0, 5, 10, 100);

        // Input: {10, 20, 30, 40} [3][2][1][0]
        // Note: Packed vector puts index 0 at LSB.
        acc_data_in = {32'd40, 32'd30, 32'd20, 32'd10}; 

        @(posedge clk);
        valid_in = 1;
        @(posedge clk);
        valid_in = 0;

        wait(valid_out);
        @(negedge clk); 

        assert_equal(valid_out, 1'b1, "Valid Out High");
        assert_equal(out_bytes[0], 8'd10, "Lane 0: 10+0=10");
        assert_equal(out_bytes[1], 8'd25, "Lane 1: 20+5=25");
        assert_equal(out_bytes[2], 8'd40, "Lane 2: 30+10=40");
        assert_equal(out_bytes[3], 8'd140, "Lane 3: 40+100=140");

        wait(!valid_out);

        // ---------------------------------------------------------
        // Test 2: Scaling & Saturation
        // ---------------------------------------------------------
        print_test_header(2, "Scaling & Saturation");

        // Reset Biases to 0
        load_biases(0,0,0,0);

        quant_mult = 2; 
        quant_shift = 1; 
        zero_point = 10;

        acc_data_in = {32'd250, 32'd50, -32'sd50, 32'd1000};

        @(posedge clk);
        valid_in = 1;
        @(posedge clk);
        valid_in = 0;

        wait(valid_out);
        @(negedge clk);

        assert_equal(out_bytes[0], 8'd255, "Lane 0: Saturation Max (1000)");
        assert_equal(out_bytes[1], 8'd0,   "Lane 1: Clamp Min (-40)");
        assert_equal(out_bytes[2], 8'd60,  "Lane 2: Normal (60)");
        assert_equal(out_bytes[3], 8'd255, "Lane 3: Saturation Max (260)");

        $finish;
    end

endmodule

