    initial begin clk=0; forever #5 clk=~clk; end

    task cpu_write(input [5:0] addr, input [31:0] data);
        begin @(posedge clk); cpu_reg_addr<=addr; cpu_reg_wdata<=data; cpu_reg_write<=1; @(posedge clk); cpu_reg_write<=0; end
    endtask

