        run_layer(`STRESS_W_BASE, `STRESS_I_BASE, `STRESS_B_BASE, `STRESS_O_BASE, `STRESS_K_TILES, 2, 1, 10, 1, "Stress Test");
        verify_ram_segment(`STRESS_O_BASE, (`STRESS_N_DIM * ARRAY_SIZE)/4, "Stress Test Results");

        // 2. Chain L1
        // L1 uses the config variable (can be 1, 2, 4 tiles, etc.)
        run_layer(`CHAIN_L1_W, `CHAIN_L1_I, `CHAIN_L1_B, `CHAIN_L1_O, `CHAIN_K_TILES, 1, 0, 0, 0, "Chain L1");

