// File: tests/tb_systolic_array.v
`timescale 1ns/1ps
`include "tests/tb_utils.vh"

module tb_systolic_array;

    // -------------------------------------------------------------------------
    // Parameters & Signals
    // -------------------------------------------------------------------------
    parameter ARRAY_SIZE = 4; // 4x4 for easy debugging
    parameter D_WIDTH = 8;
    parameter ACC_WIDTH = 32;

    logic clk;
    logic reset;
    logic weight_en;
    logic [ARRAY_SIZE*D_WIDTH-1:0] top_row_weights;

    logic data_valid_in;
    logic [ARRAY_SIZE*D_WIDTH-1:0] activations_in;
    logic [ARRAY_SIZE*ACC_WIDTH-1:0] psums_in;

    wire data_valid_out;
    wire [ARRAY_SIZE*ACC_WIDTH-1:0] psums_out;

    // Debug Unpacking
    logic [ACC_WIDTH-1:0] debug_psum_row [ARRAY_SIZE-1:0];
    genvar i;
    generate
        for (i=0; i<ARRAY_SIZE; i++) 
            assign debug_psum_row[i] = psums_out[(i+1)*ACC_WIDTH-1 : i*ACC_WIDTH];
    endgenerate

    // -------------------------------------------------------------------------
    // DUT
    // -------------------------------------------------------------------------
    systolic_array #(
        .ARRAY_SIZE(ARRAY_SIZE),
        .D_WIDTH(D_WIDTH),
        .ACC_WIDTH(ACC_WIDTH)
    ) dut (
        .clk(clk),
        .reset(reset),
        .weight_en(weight_en),
        .top_row_weights(top_row_weights),
        .data_valid_in(data_valid_in),
        .activations_in(activations_in),
        .psums_in(psums_in),
        .data_valid_out(data_valid_out),
        .psums_out(psums_out)
    );

    // -------------------------------------------------------------------------
    // Clock
    // -------------------------------------------------------------------------
    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end

    // -------------------------------------------------------------------------
    // Task: Load Identity Matrix
    // -------------------------------------------------------------------------
    task load_identity_weights;
        integer r, c;
        logic [ARRAY_SIZE*D_WIDTH-1:0] current_row_data;
        begin
            print_section("Loading Identity Weights");
            weight_en = 1;

            // Loop from Bottom Row (N-1) to Top Row (0)
            for (r = ARRAY_SIZE-1; r >= 0; r = r - 1) begin
                current_row_data = 0;

                // Construct the row vector
                for (c = 0; c < ARRAY_SIZE; c = c + 1) begin
                    // Identity: Value is 1 if row == col
                    if (r == c) begin
                        // FIX: Use Indexed Part-Select [Base +: Width]
                        current_row_data[c*D_WIDTH +: D_WIDTH] = 8'd1;
                    end else begin
                        current_row_data[c*D_WIDTH +: D_WIDTH] = 8'd0;
                    end
                end

                // Drive Signals
                top_row_weights = current_row_data;
                @(posedge clk); // Shift in
            end

            // Disable weight mode
            @(negedge clk);
            weight_en = 0;
            top_row_weights = 0;
            print_section("Weights Loaded");
        end
    endtask
    // -------------------------------------------------------------------------
    // Test Procedure
    // -------------------------------------------------------------------------
    initial begin
        `WAVE_INIT(tb_systolic_array)

        // Init
        reset = 1;
        weight_en = 0;
        top_row_weights = 0;
        data_valid_in = 0;
        activations_in = 0;
        psums_in = 0;

        @(negedge clk);
        reset = 0;

        // ---------------------------------------------------------------------
        // Test 1: Connectivity & Identity
        // ---------------------------------------------------------------------
        print_test_header(1, "Connectivity: Identity Matrix Multiplication");

        // 1. Load Weights (Identity)
        load_identity_weights();

        // 2. Drive Input Vector: {4, 3, 2, 1}
        // Input Format: Row N-1 .. Row 0. 
        // We want Act[0]=1, Act[1]=2, Act[2]=3, Act[3]=4.
        // So flat vector is {4, 3, 2, 1}

        @(posedge clk);
        data_valid_in <= 1;
        activations_in <= {8'd4, 8'd3, 8'd2, 8'd1};

        @(posedge clk);
        data_valid_in <= 0; // Single pulse
        activations_in <= 0;

        // 3. Wait for Valid Out
        // Max wait time just to be safe
        wait(data_valid_out);

        // 4. Check Result
        // Since Weights = Identity, Output should match Input {4, 3, 2, 1}
        @(negedge clk);
        assert_equal(data_valid_out, 1'b1, "Data Valid High");
        assert_equal(debug_psum_row[0], 32'd1, "Row 0 Result (1 * 1)");
        assert_equal(debug_psum_row[1], 32'd2, "Row 1 Result (2 * 1)");
        assert_equal(debug_psum_row[2], 32'd3, "Row 2 Result (3 * 1)");
        assert_equal(debug_psum_row[3], 32'd4, "Row 3 Result (4 * 1)");


        // ---------------------------------------------------------------------
        // Test 2: Latency Measurement (The Ping)
        // ---------------------------------------------------------------------
        print_test_header(2, "Latency Measurement");

        // We already saw the valid signal go high above. 
        // Let's perform a strictly timed test to verify the formula 2N-1.
        // For N=4, Expected Latency = 7.

        @(posedge clk);
        data_valid_in <= 1; 
        activations_in <= {4{8'd10}}; // All 10s

        // Count cycles until output
        // Cycle 1: Input Driven (T=0)
        @(posedge clk); 
        data_valid_in <= 0;
        activations_in <= 0;

        // We expect Valid Out at T=7.
        // We just spent 1 clock edge (T=1). Need to wait 6 more edges.
        repeat(6) @(posedge clk);

        // Check at T=7 (Post-edge)
        @(negedge clk);
        assert_equal(data_valid_out, 1'b1, "Data Valid at T = 2N - 1 (Cycle 7)");
        assert_equal(debug_psum_row[0], 32'd10, "Row 0 Output Correct");


        // ---------------------------------------------------------------------
        // Test 3: Saturation / Throughput
        // ---------------------------------------------------------------------
        print_test_header(3, "Saturation / Throughput");

        // Drive 5 consecutive valid packets
        // T=0
        @(posedge clk);
        data_valid_in <= 1; activations_in <= {4{8'd1}}; // Val = 1
        // T=1
        @(posedge clk);
        data_valid_in <= 1; activations_in <= {4{8'd2}}; // Val = 2
        // T=2
        @(posedge clk);
        data_valid_in <= 1; activations_in <= {4{8'd3}}; // Val = 3
        // T=3
        @(posedge clk);
        data_valid_in <= 1; activations_in <= {4{8'd4}}; // Val = 4
        // T=4
        @(posedge clk);
        data_valid_in <= 1; activations_in <= {4{8'd5}}; // Val = 5

        // T=5 Stop
        @(posedge clk);
        data_valid_in <= 0; activations_in <= 0;

        // Wait for pipeline latency (Latency - 1 because we are already some cycles in? 
        // No, let's just wait for valid to go High)
        wait(data_valid_out == 0); // Wait for the previous ping to finish clearing if any
        wait(data_valid_out == 1); // Wait for first packet (1)

        // Check Packet 1
        @(negedge clk);
        assert_equal(debug_psum_row[0], 32'd1, "Packet 1 Received");

        // Check Packet 2
        @(posedge clk); @(negedge clk);
        assert_equal(data_valid_out, 1'b1, "Packet 2 Valid");
        assert_equal(debug_psum_row[0], 32'd2, "Packet 2 Received");

        // Check Packet 3
        @(posedge clk); @(negedge clk);
        assert_equal(data_valid_out, 1'b1, "Packet 3 Valid");
        assert_equal(debug_psum_row[0], 32'd3, "Packet 3 Received");

        // ... (We assume if 1,2,3 pass without bubbles, 4,5 are fine)

        $finish;
    end

endmodule

