    wire done;
    wire array_weight_en;
    wire [ARRAY_SIZE*D_WIDTH-1:0] array_weights_out;
    wire [RAM_ADDR_W-1:0] ram_addr;
    logic [RAM_WIDTH-1:0] ram_rdata;

    // -------------------------------------------------------------------------
    // DUT
    // -------------------------------------------------------------------------
    weight_loader #(
        .ARRAY_SIZE(ARRAY_SIZE),
        .D_WIDTH(D_WIDTH),
        .RAM_WIDTH(RAM_WIDTH),
        .RAM_ADDR_W(RAM_ADDR_W)
    ) dut (
        .clk(clk),
        .reset(reset),
        .start(start),
        .base_addr(base_addr),
        .done(done),
        .array_weight_en(array_weight_en),
        .array_weights_out(array_weights_out),
        .ram_addr(ram_addr),
        .ram_rdata(ram_rdata)
    );

    // -------------------------------------------------------------------------
    // Simulated RAM Behavior
    // -------------------------------------------------------------------------
    // Simple response: Return data = {4'b0, Addr} to make it traceable
    always_ff @(posedge clk) begin
        ram_rdata <= {{(RAM_WIDTH-12){1'b0}}, ram_addr}; 
    end

    // -------------------------------------------------------------------------
    // Clock
    // -------------------------------------------------------------------------
    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end

    // -------------------------------------------------------------------------
    // Test Procedure
    // -------------------------------------------------------------------------
    initial begin
        `WAVE_INIT(tb_weight_loader)

        reset = 1;
        start = 0;
        base_addr = 0;

        @(negedge clk);
        reset = 0;

        // ---------------------------------------------------------------------
        // Test 1: Full Load Sequence
        // ---------------------------------------------------------------------
        print_test_header(1, "Full Weight Load Sequence");

        // Start at Address 0x100
        @(posedge clk);
        base_addr = 12'h100;
        start = 1;

        @(posedge clk);
        start = 0;

        // Monitor the sequence
        // Config: 4 Rows. Width=32 bits. RAM=16 bits.
        // Needs 2 reads per row. Total 8 reads. Total 4 Pushes.

        // Wait for Done
        wait(done);
        @(negedge clk);
        assert_equal(done, 1'b1, "Loader finished");

        print_section("Manual Waveform Inspection Required for exact timing");
        // We will perform a specific check on the last packet
        // Last Row should be Row 3.
        // It consists of Read 6 (Addr 0x118) and Read 7 (Addr 0x11C) -> (Assuming +4 increment)
        // With RAM logic returning address:
        // LSBs = 0x118, MSBs = 0x11C.
        // Expected: 0x11C118

        // Note: The DUT uses +4 increment for byte addressing simulation.
        // 0x100, 104, 108, 10C, 110, 114, 118, 11C

        // Since we are at DONE, the array_weights_out should hold the LAST row pushed.
        assert_equal(array_weights_out, 32'h011C0118, "Last Row Packed Correctly");

        $finish;
    end

    // -------------------------------------------------------------------------
    // Spy on the Push Signal
    // -------------------------------------------------------------------------
    integer push_count = 0;
    always @(posedge clk) begin
        if (array_weight_en) begin
            push_count <= push_count + 1;
            $display("  [TB] PUSH %0d: Data=0x%h", push_count, array_weights_out);
        end
    end

endmodule

